from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional


VALID_SIDE_VALUES = {"BUY", "SELL", "LONG", "SHORT"}


class ChainStrategyBudgetPolicyError(RuntimeError):
    """Raised when chain/strategy budget policy inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise ChainStrategyBudgetPolicyError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_chain(value: Any) -> str:
    return _require_non_empty_string("chain", value).lower()


def _normalize_strategy_id(value: Any) -> str:
    return _require_non_empty_string("strategy_id", value).lower()


def _normalize_symbol(value: Any) -> str:
    return _require_non_empty_string("symbol", value).upper()


def _normalize_pair(value: Any) -> str:
    return _require_non_empty_string("pair", value).upper()


def _normalize_side(value: Any) -> str:
    normalized = _require_non_empty_string("side", value).upper()
    if normalized not in VALID_SIDE_VALUES:
        raise ChainStrategyBudgetPolicyError(
            f"side must be one of {sorted(VALID_SIDE_VALUES)}"
        )
    return normalized


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a non-negative integer")
    if value < 0:
        raise ChainStrategyBudgetPolicyError(f"{name} must be a non-negative integer")
    return value


def _normalize_optional_positive_int(name: str, value: Any) -> Optional[int]:
    if value is None:
        return None
    if isinstance(value, bool) or not isinstance(value, int):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a positive integer when provided")
    if value <= 0:
        raise ChainStrategyBudgetPolicyError(f"{name} must be a positive integer when provided")
    return value


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if isinstance(value, bool):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise ChainStrategyBudgetPolicyError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise ChainStrategyBudgetPolicyError(f"{name} must be a non-negative number")
    return normalized


def _normalize_positive_float(name: str, value: Any) -> float:
    normalized = _normalize_non_negative_float(name, value)
    if normalized <= 0.0:
        raise ChainStrategyBudgetPolicyError(f"{name} must be a positive number")
    return normalized


def _normalize_optional_positive_float(name: str, value: Any) -> Optional[float]:
    if value is None:
        return None
    normalized = _normalize_non_negative_float(name, value)
    if normalized <= 0.0:
        raise ChainStrategyBudgetPolicyError(f"{name} must be a positive number when provided")
    return normalized


def _normalize_optional_non_negative_float(name: str, value: Any) -> Optional[float]:
    if value is None:
        return None
    return _normalize_non_negative_float(name, value)


def _normalize_bool(name: str, value: Any) -> bool:
    if not isinstance(value, bool):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a bool")
    return value


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise ChainStrategyBudgetPolicyError("metadata must be a mapping when provided")
    return dict(value)


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a list when provided")
    normalized: List[str] = []
    for item in value:
        normalized.append(_require_non_empty_string(f"{name}[]", item).lower())
    return normalized


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise ChainStrategyBudgetPolicyError(f"{name} is required")

    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise ChainStrategyBudgetPolicyError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise ChainStrategyBudgetPolicyError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise ChainStrategyBudgetPolicyError(f"{name} must be mapping-like or expose to_dict()")


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


@dataclass(frozen=True)
class ChainBudget:
    chain: str
    max_total_exposure_usd: float
    max_active_positions: Optional[int] = None
    max_new_allocation_usd: Optional[float] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    chain_budget_id: str = field(init=False)

    def __post_init__(self) -> None:
        normalized_chain = _normalize_chain(self.chain)
        normalized_max_total_exposure_usd = _normalize_positive_float(
            "max_total_exposure_usd",
            self.max_total_exposure_usd,
        )
        normalized_max_active_positions = _normalize_optional_positive_int(
            "max_active_positions",
            self.max_active_positions,
        )
        normalized_max_new_allocation_usd = _normalize_optional_positive_float(
            "max_new_allocation_usd",
            self.max_new_allocation_usd,
        )
        normalized_metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "chain", normalized_chain)
        object.__setattr__(self, "max_total_exposure_usd", normalized_max_total_exposure_usd)
        object.__setattr__(self, "max_active_positions", normalized_max_active_positions)
        object.__setattr__(self, "max_new_allocation_usd", normalized_max_new_allocation_usd)
        object.__setattr__(self, "metadata", normalized_metadata)
        object.__setattr__(
            self,
            "chain_budget_id",
            _stable_id(
                "chain_budget",
                {
                    "chain": normalized_chain,
                    "max_total_exposure_usd": normalized_max_total_exposure_usd,
                    "max_active_positions": normalized_max_active_positions,
                    "max_new_allocation_usd": normalized_max_new_allocation_usd,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        payload = asdict(self)
        payload["metadata"] = dict(self.metadata)
        return payload

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "ChainBudget":
        if not isinstance(payload, Mapping):
            raise ChainStrategyBudgetPolicyError("payload must be a mapping")
        return cls(
            chain=payload.get("chain"),
            max_total_exposure_usd=payload.get("max_total_exposure_usd"),
            max_active_positions=payload.get("max_active_positions"),
            max_new_allocation_usd=payload.get("max_new_allocation_usd"),
            metadata=dict(payload.get("metadata") or {}),
        )


