            max_active_positions=payload.get("max_active_positions"),
            max_new_allocation_usd=payload.get("max_new_allocation_usd"),
            allowed_chains=list(payload.get("allowed_chains") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class ChainStrategyBudgetPolicy:
    chain_budgets: List[ChainBudget] = field(default_factory=list)
    strategy_budgets: List[StrategyBudget] = field(default_factory=list)
    require_explicit_chain_budget: bool = True
    require_explicit_strategy_budget: bool = True
    max_total_active_positions: Optional[int] = None
    max_positions_per_symbol: Optional[int] = None
    max_positions_per_pair: Optional[int] = None
    max_positions_per_side: Optional[int] = None
    max_exposure_per_symbol_usd: Optional[float] = None
    max_exposure_per_pair_usd: Optional[float] = None
    max_exposure_per_side_usd: Optional[float] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    chain_strategy_budget_policy_id: str = field(init=False)

    def __post_init__(self) -> None:
        normalized_chain_budgets = [
            item if isinstance(item, ChainBudget) else ChainBudget.from_dict(_mapping_from_value("chain_budget", item))
            for item in self.chain_budgets
        ]
        normalized_strategy_budgets = [
            item if isinstance(item, StrategyBudget) else StrategyBudget.from_dict(_mapping_from_value("strategy_budget", item))
            for item in self.strategy_budgets
        ]
        normalized_require_explicit_chain_budget = _normalize_bool(
            "require_explicit_chain_budget",
            self.require_explicit_chain_budget,
        )
        normalized_require_explicit_strategy_budget = _normalize_bool(
            "require_explicit_strategy_budget",
            self.require_explicit_strategy_budget,
        )
        normalized_max_total_active_positions = _normalize_optional_positive_int(
            "max_total_active_positions",
            self.max_total_active_positions,
        )
        normalized_max_positions_per_symbol = _normalize_optional_positive_int(
            "max_positions_per_symbol",
            self.max_positions_per_symbol,
        )
        normalized_max_positions_per_pair = _normalize_optional_positive_int(
            "max_positions_per_pair",
            self.max_positions_per_pair,
        )
        normalized_max_positions_per_side = _normalize_optional_positive_int(
            "max_positions_per_side",
            self.max_positions_per_side,
        )
        normalized_max_exposure_per_symbol_usd = _normalize_optional_positive_float(
            "max_exposure_per_symbol_usd",
            self.max_exposure_per_symbol_usd,
        )
        normalized_max_exposure_per_pair_usd = _normalize_optional_positive_float(
            "max_exposure_per_pair_usd",
            self.max_exposure_per_pair_usd,
        )
        normalized_max_exposure_per_side_usd = _normalize_optional_positive_float(
            "max_exposure_per_side_usd",
            self.max_exposure_per_side_usd,
        )
        normalized_metadata = _normalize_metadata(self.metadata)

        if len({item.chain for item in normalized_chain_budgets}) != len(normalized_chain_budgets):
            raise ChainStrategyBudgetPolicyError("chain_budgets must not contain duplicate chains")
        if len({item.strategy_id for item in normalized_strategy_budgets}) != len(normalized_strategy_budgets):
            raise ChainStrategyBudgetPolicyError("strategy_budgets must not contain duplicate strategy_id values")

        object.__setattr__(self, "chain_budgets", normalized_chain_budgets)
        object.__setattr__(self, "strategy_budgets", normalized_strategy_budgets)
        object.__setattr__(self, "require_explicit_chain_budget", normalized_require_explicit_chain_budget)
        object.__setattr__(self, "require_explicit_strategy_budget", normalized_require_explicit_strategy_budget)
        object.__setattr__(self, "max_total_active_positions", normalized_max_total_active_positions)
        object.__setattr__(self, "max_positions_per_symbol", normalized_max_positions_per_symbol)
        object.__setattr__(self, "max_positions_per_pair", normalized_max_positions_per_pair)
        object.__setattr__(self, "max_positions_per_side", normalized_max_positions_per_side)
        object.__setattr__(self, "max_exposure_per_symbol_usd", normalized_max_exposure_per_symbol_usd)
        object.__setattr__(self, "max_exposure_per_pair_usd", normalized_max_exposure_per_pair_usd)
        object.__setattr__(self, "max_exposure_per_side_usd", normalized_max_exposure_per_side_usd)
        object.__setattr__(self, "metadata", normalized_metadata)
        object.__setattr__(
            self,
            "chain_strategy_budget_policy_id",
            _stable_id(
                "chain_strategy_budget_policy",
                {
                    "chain_budgets": [item.to_dict() for item in normalized_chain_budgets],
                    "strategy_budgets": [item.to_dict() for item in normalized_strategy_budgets],
                    "require_explicit_chain_budget": normalized_require_explicit_chain_budget,
                    "require_explicit_strategy_budget": normalized_require_explicit_strategy_budget,
                    "max_total_active_positions": normalized_max_total_active_positions,
                    "max_positions_per_symbol": normalized_max_positions_per_symbol,
                    "max_positions_per_pair": normalized_max_positions_per_pair,
                    "max_positions_per_side": normalized_max_positions_per_side,
                    "max_exposure_per_symbol_usd": normalized_max_exposure_per_symbol_usd,
                    "max_exposure_per_pair_usd": normalized_max_exposure_per_pair_usd,
                    "max_exposure_per_side_usd": normalized_max_exposure_per_side_usd,
                },
            ),
        )

    def chain_budget_by_chain(self) -> Dict[str, ChainBudget]:
        return {item.chain: item for item in self.chain_budgets}

    def strategy_budget_by_id(self) -> Dict[str, StrategyBudget]:
        return {item.strategy_id: item for item in self.strategy_budgets}

    def to_dict(self) -> Dict[str, Any]:
        return {
            "chain_budgets": [item.to_dict() for item in self.chain_budgets],
            "strategy_budgets": [item.to_dict() for item in self.strategy_budgets],
            "require_explicit_chain_budget": self.require_explicit_chain_budget,
            "require_explicit_strategy_budget": self.require_explicit_strategy_budget,
            "max_total_active_positions": self.max_total_active_positions,
            "max_positions_per_symbol": self.max_positions_per_symbol,
            "max_positions_per_pair": self.max_positions_per_pair,
            "max_positions_per_side": self.max_positions_per_side,
            "max_exposure_per_symbol_usd": self.max_exposure_per_symbol_usd,
            "max_exposure_per_pair_usd": self.max_exposure_per_pair_usd,
            "max_exposure_per_side_usd": self.max_exposure_per_side_usd,
            "metadata": dict(self.metadata),
            "chain_strategy_budget_policy_id": self.chain_strategy_budget_policy_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "ChainStrategyBudgetPolicy":
        if not isinstance(payload, Mapping):
            raise ChainStrategyBudgetPolicyError("payload must be a mapping")
        return cls(
            chain_budgets=list(payload.get("chain_budgets") or []),
            strategy_budgets=list(payload.get("strategy_budgets") or []),
            require_explicit_chain_budget=payload.get("require_explicit_chain_budget", True),
            require_explicit_strategy_budget=payload.get("require_explicit_strategy_budget", True),
            max_total_active_positions=payload.get("max_total_active_positions"),
            max_positions_per_symbol=payload.get("max_positions_per_symbol"),
            max_positions_per_pair=payload.get("max_positions_per_pair"),
            max_positions_per_side=payload.get("max_positions_per_side"),
            max_exposure_per_symbol_usd=payload.get("max_exposure_per_symbol_usd"),
            max_exposure_per_pair_usd=payload.get("max_exposure_per_pair_usd"),
            max_exposure_per_side_usd=payload.get("max_exposure_per_side_usd"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class BudgetedExposureCandidate:
    chain: str
    strategy_id: str
    symbol: str
    side: str
    proposed_exposure_usd: float
    pair: Optional[str] = None
    proposed_position_delta: int = 1
    metadata: Dict[str, Any] = field(default_factory=dict)
    budget_candidate_key: str = field(init=False)

    def __post_init__(self) -> None:
        normalized_chain = _normalize_chain(self.chain)
        normalized_strategy_id = _normalize_strategy_id(self.strategy_id)
        normalized_symbol = _normalize_symbol(self.symbol)
        normalized_pair = _normalize_pair(self.pair or self.symbol)
        normalized_side = _normalize_side(self.side)
        normalized_proposed_exposure_usd = _normalize_positive_float(
            "proposed_exposure_usd",
            self.proposed_exposure_usd,
        )
        normalized_proposed_position_delta = _normalize_optional_positive_int(
            "proposed_position_delta",
            self.proposed_position_delta,
        )
        assert normalized_proposed_position_delta is not None
        normalized_metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "chain", normalized_chain)
        object.__setattr__(self, "strategy_id", normalized_strategy_id)
        object.__setattr__(self, "symbol", normalized_symbol)
        object.__setattr__(self, "pair", normalized_pair)
        object.__setattr__(self, "side", normalized_side)
        object.__setattr__(self, "proposed_exposure_usd", normalized_proposed_exposure_usd)
        object.__setattr__(self, "proposed_position_delta", normalized_proposed_position_delta)
        object.__setattr__(self, "metadata", normalized_metadata)
        object.__setattr__(
            self,
            "budget_candidate_key",
            _stable_id(
                "budget_candidate",
                {
                    "chain": normalized_chain,
                    "strategy_id": normalized_strategy_id,
                    "symbol": normalized_symbol,
                    "pair": normalized_pair,
                    "side": normalized_side,
                    "proposed_exposure_usd": normalized_proposed_exposure_usd,
                    "proposed_position_delta": normalized_proposed_position_delta,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        payload = asdict(self)
        payload["metadata"] = dict(self.metadata)
        return payload

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "BudgetedExposureCandidate":
        if not isinstance(payload, Mapping):
            raise ChainStrategyBudgetPolicyError("payload must be a mapping")
        return cls(
            chain=payload.get("chain"),
            strategy_id=payload.get("strategy_id"),
            symbol=payload.get("symbol"),
            pair=payload.get("pair"),
            side=payload.get("side"),
            proposed_exposure_usd=payload.get("proposed_exposure_usd"),
            proposed_position_delta=payload.get("proposed_position_delta", 1),
            metadata=dict(payload.get("metadata") or {}),
        )


