@dataclass(frozen=True)
class ChainStrategyBudgetPolicyResult:
    chain_strategy_budget_policy_id: str
    budget_candidate_key: str
    chain: str
    strategy_id: str
    symbol: str
    pair: str
    side: str
    proposed_exposure_usd: float
    active_position_count: int
    projected_active_position_count: int
    chain_active_exposure_usd: float
    projected_chain_active_exposure_usd: float
    strategy_active_exposure_usd: float
    projected_strategy_active_exposure_usd: float
    symbol_active_exposure_usd: float
    projected_symbol_active_exposure_usd: float
    pair_active_exposure_usd: float
    projected_pair_active_exposure_usd: float
    side_active_exposure_usd: float
    projected_side_active_exposure_usd: float
    free_capital_before_chain_usd: Optional[float]
    projected_chain_free_capital_after_usd: Optional[float]
    should_allow_allocation: bool
    is_blocked: bool
    block_reasons: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        object.__setattr__(
            self,
            "chain_strategy_budget_policy_id",
            _require_non_empty_string("chain_strategy_budget_policy_id", self.chain_strategy_budget_policy_id),
        )
        object.__setattr__(self, "budget_candidate_key", _require_non_empty_string("budget_candidate_key", self.budget_candidate_key))
        object.__setattr__(self, "chain", _normalize_chain(self.chain))
        object.__setattr__(self, "strategy_id", _normalize_strategy_id(self.strategy_id))
        object.__setattr__(self, "symbol", _normalize_symbol(self.symbol))
        object.__setattr__(self, "pair", _normalize_pair(self.pair))
        object.__setattr__(self, "side", _normalize_side(self.side))
        object.__setattr__(self, "proposed_exposure_usd", _normalize_positive_float("proposed_exposure_usd", self.proposed_exposure_usd))
        object.__setattr__(self, "active_position_count", _normalize_non_negative_int("active_position_count", self.active_position_count))
        object.__setattr__(self, "projected_active_position_count", _normalize_non_negative_int("projected_active_position_count", self.projected_active_position_count))

        for name in (
            "chain_active_exposure_usd",
            "projected_chain_active_exposure_usd",
            "strategy_active_exposure_usd",
            "projected_strategy_active_exposure_usd",
            "symbol_active_exposure_usd",
            "projected_symbol_active_exposure_usd",
            "pair_active_exposure_usd",
            "projected_pair_active_exposure_usd",
            "side_active_exposure_usd",
            "projected_side_active_exposure_usd",
        ):
            object.__setattr__(self, name, _normalize_non_negative_float(name, getattr(self, name)))

        if self.free_capital_before_chain_usd is not None:
            object.__setattr__(self, "free_capital_before_chain_usd", _normalize_non_negative_float("free_capital_before_chain_usd", self.free_capital_before_chain_usd))
        if self.projected_chain_free_capital_after_usd is not None:
            object.__setattr__(self, "projected_chain_free_capital_after_usd", _normalize_non_negative_float("projected_chain_free_capital_after_usd", self.projected_chain_free_capital_after_usd))

        if not isinstance(self.should_allow_allocation, bool):
            raise ChainStrategyBudgetPolicyError("should_allow_allocation must be a bool")
        if not isinstance(self.is_blocked, bool):
            raise ChainStrategyBudgetPolicyError("is_blocked must be a bool")
        if self.should_allow_allocation == self.is_blocked:
            raise ChainStrategyBudgetPolicyError("should_allow_allocation and is_blocked must always be opposite booleans")

        if not isinstance(self.block_reasons, list):
            raise ChainStrategyBudgetPolicyError("block_reasons must be a list")
        for reason in self.block_reasons:
            _require_non_empty_string("block_reasons[]", reason)

        object.__setattr__(self, "metadata", _normalize_metadata(self.metadata))

    def to_dict(self) -> Dict[str, Any]:
        payload = asdict(self)
        payload["metadata"] = dict(self.metadata)
        payload["block_reasons"] = list(self.block_reasons)
        return payload


def normalize_chain_strategy_budget_policy(policy: Any) -> ChainStrategyBudgetPolicy:
    if isinstance(policy, ChainStrategyBudgetPolicy):
        return policy
    if isinstance(policy, Mapping):
        return ChainStrategyBudgetPolicy.from_dict(policy)
    raise ChainStrategyBudgetPolicyError("policy must be a ChainStrategyBudgetPolicy or mapping")


def normalize_budgeted_exposure_candidate(candidate: Any) -> BudgetedExposureCandidate:
    if isinstance(candidate, BudgetedExposureCandidate):
        return candidate
    payload = _mapping_from_value("candidate", candidate)
    return BudgetedExposureCandidate.from_dict(payload)


def _extract_bucket_exposure(payload: Mapping[str, Any]) -> float:
    for name in (
        "exposure_usd",
        "total_exposure_usd",
        "gross_exposure_usd",
        "active_exposure_usd",
        "notional_usd",
    ):
        if name in payload and payload.get(name) is not None:
            return _normalize_non_negative_float(name, payload.get(name))
    return 0.0


def _extract_bucket_position_count(payload: Mapping[str, Any]) -> int:
    for name in (
        "position_count",
        "active_position_count",
        "positions",
    ):
        if name in payload and payload.get(name) is not None:
            return _normalize_non_negative_int(name, payload.get(name))
    return 0


def _normalize_bucket_map(name: str, value: Any, key_normalizer) -> Dict[str, AggregateBucket]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise ChainStrategyBudgetPolicyError(f"{name} must be a mapping when provided")
    normalized: Dict[str, AggregateBucket] = {}
    for raw_key, raw_value in value.items():
        key = key_normalizer(raw_key)
        if isinstance(raw_value, (int, float, str)):
            bucket = AggregateBucket(exposure_usd=raw_value, position_count=0)
        else:
            payload = _mapping_from_value(f"{name}[{raw_key}]", raw_value)
            bucket = AggregateBucket(
                exposure_usd=_extract_bucket_exposure(payload),
                position_count=_extract_bucket_position_count(payload),
            )
        normalized[key] = bucket
    return normalized


def normalize_exposure_aggregate(exposure_aggregate: Any) -> NormalizedExposureAggregate:
    payload = _mapping_from_value("exposure_aggregate", exposure_aggregate)
    total_active_positions = _normalize_non_negative_int(
        "total_active_positions",
        int(payload.get("total_active_positions", 0)),
    )
    return NormalizedExposureAggregate(
        total_active_positions=total_active_positions,
        by_chain=_normalize_bucket_map("by_chain", payload.get("by_chain"), _normalize_chain),
        by_strategy=_normalize_bucket_map("by_strategy", payload.get("by_strategy"), _normalize_strategy_id),
        by_symbol=_normalize_bucket_map("by_symbol", payload.get("by_symbol"), _normalize_symbol),
        by_pair=_normalize_bucket_map("by_pair", payload.get("by_pair"), _normalize_pair),
        by_side=_normalize_bucket_map("by_side", payload.get("by_side"), _normalize_side),
    )


def _normalize_portfolio_state_snapshot(snapshot: Any) -> Dict[str, Any]:
    if snapshot is None:
        return {}
    payload = _mapping_from_value("portfolio_state_snapshot", snapshot)
    free_capital_by_chain = payload.get("free_capital_by_chain")
    if free_capital_by_chain is None:
        return {}
    if not isinstance(free_capital_by_chain, Mapping):
        raise ChainStrategyBudgetPolicyError("portfolio_state_snapshot.free_capital_by_chain must be a mapping")
    normalized: Dict[str, float] = {}
    for raw_key, raw_value in free_capital_by_chain.items():
        normalized[_normalize_chain(raw_key)] = _normalize_non_negative_float(
            f"free_capital_by_chain[{raw_key}]",
            raw_value,
        )
    return normalized


def _bucket(bucket_map: Mapping[str, AggregateBucket], key: str) -> AggregateBucket:
    return bucket_map.get(key, AggregateBucket())


def evaluate_chain_strategy_budget_policy(
    *,
    policy: Any,
    candidate: Any,
    exposure_aggregate: Any,
    portfolio_state_snapshot: Any | None = None,
) -> ChainStrategyBudgetPolicyResult:
    normalized_policy = normalize_chain_strategy_budget_policy(policy)
    normalized_candidate = normalize_budgeted_exposure_candidate(candidate)
    normalized_aggregate = normalize_exposure_aggregate(exposure_aggregate)
    free_capital_by_chain = _normalize_portfolio_state_snapshot(portfolio_state_snapshot)

    chain_budget = normalized_policy.chain_budget_by_chain().get(normalized_candidate.chain)
    strategy_budget = normalized_policy.strategy_budget_by_id().get(normalized_candidate.strategy_id)

    chain_bucket = _bucket(normalized_aggregate.by_chain, normalized_candidate.chain)
    strategy_bucket = _bucket(normalized_aggregate.by_strategy, normalized_candidate.strategy_id)
    symbol_bucket = _bucket(normalized_aggregate.by_symbol, normalized_candidate.symbol)
    pair_bucket = _bucket(normalized_aggregate.by_pair, normalized_candidate.pair)
    side_bucket = _bucket(normalized_aggregate.by_side, normalized_candidate.side)

    active_position_count = normalized_aggregate.total_active_positions
    projected_active_position_count = active_position_count + normalized_candidate.proposed_position_delta

    projected_chain_active_exposure_usd = chain_bucket.exposure_usd + normalized_candidate.proposed_exposure_usd
    projected_strategy_active_exposure_usd = strategy_bucket.exposure_usd + normalized_candidate.proposed_exposure_usd
    projected_symbol_active_exposure_usd = symbol_bucket.exposure_usd + normalized_candidate.proposed_exposure_usd
    projected_pair_active_exposure_usd = pair_bucket.exposure_usd + normalized_candidate.proposed_exposure_usd
    projected_side_active_exposure_usd = side_bucket.exposure_usd + normalized_candidate.proposed_exposure_usd

    free_capital_before_chain_usd = free_capital_by_chain.get(normalized_candidate.chain)
    projected_chain_free_capital_after_usd: Optional[float] = None
    if free_capital_before_chain_usd is not None:
        projected_chain_free_capital_after_usd = max(
            0.0,
            free_capital_before_chain_usd - normalized_candidate.proposed_exposure_usd,
        )

    block_reasons: List[str] = []

    if normalized_policy.require_explicit_chain_budget and chain_budget is None:
        block_reasons.append(
            f"no explicit chain budget configured for chain: {normalized_candidate.chain}"
        )

    if normalized_policy.require_explicit_strategy_budget and strategy_budget is None:
        block_reasons.append(
            f"no explicit strategy budget configured for strategy_id: {normalized_candidate.strategy_id}"
        )

    if chain_budget is not None:
        if chain_budget.max_new_allocation_usd is not None and normalized_candidate.proposed_exposure_usd > chain_budget.max_new_allocation_usd:
            block_reasons.append(
                "proposed exposure would exceed chain max_new_allocation_usd"
            )
        if projected_chain_active_exposure_usd > chain_budget.max_total_exposure_usd:
            block_reasons.append(
                "projected chain exposure would exceed chain max_total_exposure_usd"
            )
        if chain_budget.max_active_positions is not None:
            projected_chain_positions = chain_bucket.position_count + normalized_candidate.proposed_position_delta
            if projected_chain_positions > chain_budget.max_active_positions:
                block_reasons.append(
                    "projected chain position count would exceed chain max_active_positions"
                )

    if strategy_budget is not None:
        if strategy_budget.allowed_chains and normalized_candidate.chain not in strategy_budget.allowed_chains:
            block_reasons.append(
                "candidate chain is not allowed by strategy budget"
            )
        if strategy_budget.max_new_allocation_usd is not None and normalized_candidate.proposed_exposure_usd > strategy_budget.max_new_allocation_usd:
            block_reasons.append(
                "proposed exposure would exceed strategy max_new_allocation_usd"
            )
        if projected_strategy_active_exposure_usd > strategy_budget.max_total_exposure_usd:
            block_reasons.append(
                "projected strategy exposure would exceed strategy max_total_exposure_usd"
            )
        if strategy_budget.max_active_positions is not None:
            projected_strategy_positions = strategy_bucket.position_count + normalized_candidate.proposed_position_delta
            if projected_strategy_positions > strategy_budget.max_active_positions:
                block_reasons.append(
                    "projected strategy position count would exceed strategy max_active_positions"
                )

    if normalized_policy.max_total_active_positions is not None and projected_active_position_count > normalized_policy.max_total_active_positions:
        block_reasons.append(
            "projected active position count would exceed max_total_active_positions"
        )

    projected_symbol_positions = symbol_bucket.position_count + normalized_candidate.proposed_position_delta
    projected_pair_positions = pair_bucket.position_count + normalized_candidate.proposed_position_delta
    projected_side_positions = side_bucket.position_count + normalized_candidate.proposed_position_delta

    if normalized_policy.max_positions_per_symbol is not None and projected_symbol_positions > normalized_policy.max_positions_per_symbol:
        block_reasons.append(
            "projected symbol position count would exceed max_positions_per_symbol"
        )
    if normalized_policy.max_positions_per_pair is not None and projected_pair_positions > normalized_policy.max_positions_per_pair:
        block_reasons.append(
            "projected pair position count would exceed max_positions_per_pair"
        )
    if normalized_policy.max_positions_per_side is not None and projected_side_positions > normalized_policy.max_positions_per_side:
        block_reasons.append(
            "projected side position count would exceed max_positions_per_side"
        )

    if normalized_policy.max_exposure_per_symbol_usd is not None and projected_symbol_active_exposure_usd > normalized_policy.max_exposure_per_symbol_usd:
        block_reasons.append(
            "projected symbol exposure would exceed max_exposure_per_symbol_usd"
        )
    if normalized_policy.max_exposure_per_pair_usd is not None and projected_pair_active_exposure_usd > normalized_policy.max_exposure_per_pair_usd:
        block_reasons.append(
            "projected pair exposure would exceed max_exposure_per_pair_usd"
        )
    if normalized_policy.max_exposure_per_side_usd is not None and projected_side_active_exposure_usd > normalized_policy.max_exposure_per_side_usd:
        block_reasons.append(
            "projected side exposure would exceed max_exposure_per_side_usd"
        )

    if free_capital_before_chain_usd is not None and normalized_candidate.proposed_exposure_usd > free_capital_before_chain_usd:
        block_reasons.append(
            "chain free capital would be insufficient for proposed exposure"
        )

    should_allow_allocation = len(block_reasons) == 0
    is_blocked = not should_allow_allocation

    return ChainStrategyBudgetPolicyResult(
        chain_strategy_budget_policy_id=normalized_policy.chain_strategy_budget_policy_id,
        budget_candidate_key=normalized_candidate.budget_candidate_key,
        chain=normalized_candidate.chain,
        strategy_id=normalized_candidate.strategy_id,
        symbol=normalized_candidate.symbol,
        pair=normalized_candidate.pair,
        side=normalized_candidate.side,
        proposed_exposure_usd=normalized_candidate.proposed_exposure_usd,
        active_position_count=active_position_count,
        projected_active_position_count=projected_active_position_count,
        chain_active_exposure_usd=chain_bucket.exposure_usd,
        projected_chain_active_exposure_usd=projected_chain_active_exposure_usd,
        strategy_active_exposure_usd=strategy_bucket.exposure_usd,
        projected_strategy_active_exposure_usd=projected_strategy_active_exposure_usd,
        symbol_active_exposure_usd=symbol_bucket.exposure_usd,
        projected_symbol_active_exposure_usd=projected_symbol_active_exposure_usd,
        pair_active_exposure_usd=pair_bucket.exposure_usd,
        projected_pair_active_exposure_usd=projected_pair_active_exposure_usd,
        side_active_exposure_usd=side_bucket.exposure_usd,
        projected_side_active_exposure_usd=projected_side_active_exposure_usd,
        free_capital_before_chain_usd=free_capital_before_chain_usd,
        projected_chain_free_capital_after_usd=projected_chain_free_capital_after_usd,
        should_allow_allocation=should_allow_allocation,
        is_blocked=is_blocked,
        block_reasons=block_reasons,
        metadata=dict(normalized_candidate.metadata),
    )


def should_allow_under_chain_strategy_budget_policy(
    *,
    policy: Any,
    candidate: Any,
    exposure_aggregate: Any,
    portfolio_state_snapshot: Any | None = None,
) -> bool:
    result = evaluate_chain_strategy_budget_policy(
        policy=policy,
        candidate=candidate,
        exposure_aggregate=exposure_aggregate,
        portfolio_state_snapshot=portfolio_state_snapshot,
    )
    return result.should_allow_allocation
